scenarios.code:
"use client";
import { MorphingCardStack } from "@/components/ui/morphing-card-stack";
import { Zap, Palette, Shield } from "lucide-react";

const features = [
  { id: "speed", title: "Blazing Fast", description: "60 fps animations with zero layout thrash.", icon: <Zap className="w-5 h-5" />, color: "#6366f120" },
  { id: "design", title: "Beautiful", description: "Crafted with care for every pixel and motion curve.", icon: <Palette className="w-5 h-5" />, color: "#a855f720" },
  { id: "safe", title: "Production Safe", description: "Fully typed, accessible, and tested.", icon: <Shield className="w-5 h-5" />, color: "#22c55e20" },
];

export default function FeatureStack() {
  return (
    <div className="flex items-center justify-center p-10">
      <MorphingCardStack cards={features} defaultLayout="stack" />
    </div>
  );
}

